List<Article> found = catalog.findWithAllTags(required);
System.out.println("Java + beginner: " + found.size() + " article(s)");

// Tags in at least 2 articles
System.out.println("Popular tags: " + catalog.popularTags(2));
```

worked_example.final_code:
import java.util.*;

class Article {
    private final String title;
    private final Set<String> tags = new HashSet<>();

    public Article(String title, String... initialTags) {
        this.title = title;
        Collections.addAll(tags, initialTags);
    }

    public boolean hasTag(String tag) { return tags.contains(tag); }
    public Set<String> getTags() { return new HashSet<>(tags); }
    public String getTitle() { return title; }
    public String toString() { return title + " " + tags; }
}

class TagCatalog {
    private List<Article> articles = new ArrayList<>();

    public void add(Article a) { articles.add(a); }

    public List<Article> findWithAllTags(Set<String> required) {
        List<Article> result = new ArrayList<>();
        for (Article a : articles) {
            if (a.getTags().containsAll(required)) result.add(a);
        }
        return result;
    }

    public Set<String> allTags() {
        Set<String> all = new HashSet<>();
        for (Article a : articles) all.addAll(a.getTags());
        return all;
    }

    public Set<String> popularTags(int minArticles) {
        Map<String, Integer> count = new HashMap<>();
        for (Article a : articles)
            for (String tag : a.getTags())
                count.put(tag, count.getOrDefault(tag, 0) + 1);
        Set<String> popular = new HashSet<>();
        for (Map.Entry<String, Integer> e : count.entrySet())
            if (e.getValue() >= minArticles) popular.add(e.getKey());
        return popular;
    }
}

public class TagSystem {
    public static void main(String[] args) {
        TagCatalog catalog = new TagCatalog();
        catalog.add(new Article("Java Basics",       "java", "beginner", "programming"));
        catalog.add(new Article("OOP in Java",        "java", "oop",     "programming"));
        catalog.add(new Article("Python vs Java",     "java", "python",  "comparison"));
        catalog.add(new Article("Python for Data",    "python", "data-science", "beginner"));

        List<String> allTagsSorted = new ArrayList<>(catalog.allTags());
        Collections.sort(allTagsSorted);
        System.out.println("All tags: " + allTagsSorted);

        Set<String> required = new HashSet<>(Arrays.asList("java", "beginner"));
        List<Article> found = catalog.findWithAllTags(required);
        System.out.println("Java + beginner: " + found.size() + " article(s)");
        for (Article a : found) System.out.println("  " + a.getTitle());

        List<String> popular = new ArrayList<>(catalog.popularTags(2));
        Collections.sort(popular);
        System.out.println("Popular (2+ articles): " + popular);
    }
}
